package servlets;

import dao.StudentDAO;
import dao.StudentDAOImpl;
import dao.UserDAO;
import dao.UserDAOImpl;
import models.Student;
import models.User;

import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServlet;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;

import java.io.IOException;
import java.sql.Date;
import java.util.List;

public class StudentServlet extends HttpServlet {
    private final StudentDAO studentDAO = new StudentDAOImpl();
    private final UserDAO userDAO = new UserDAOImpl();

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String action = request.getParameter("action");
        if ("list".equals(action) || action == null) {
            List<Student> students = studentDAO.getAll();
            request.setAttribute("students", students);
            request.getRequestDispatcher("admin/students.jsp").forward(request, response);
        } else if ("edit".equals(action)) {
            int id = Integer.parseInt(request.getParameter("id"));
            Student student = studentDAO.read(id);
            User user = userDAO.read(student.getUserId());
            request.setAttribute("student", student);
            request.setAttribute("user", user);
            request.getRequestDispatcher("admin/editStudent.jsp").forward(request, response);
        } else if ("delete".equals(action)) {
            int id = Integer.parseInt(request.getParameter("id"));
            Student student = studentDAO.read(id);
            if (student != null) {
                userDAO.delete(student.getUserId());
            }
            studentDAO.delete(id);
            response.sendRedirect("StudentServlet?action=list");
        } else if ("add".equals(action)) {
            request.getRequestDispatcher("admin/addStudent.jsp").forward(request, response);
        }
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String action = request.getParameter("action");
        if ("add".equals(action)) {
            // Create user first
            String username = request.getParameter("username");
            String password = request.getParameter("password");
            User user = new User(0, username, password, "student");
            userDAO.create(user);
            // user.getId() is already set by create() method

            // Create student
            String firstName = request.getParameter("firstName");
            String lastName = request.getParameter("lastName");
            String email = request.getParameter("email");
            String phone = request.getParameter("phone");
            String address = request.getParameter("address");
            Date dob = Date.valueOf(request.getParameter("dob"));
            Date enrollment = new Date(System.currentTimeMillis());

            Student student = new Student(0, user.getId(), firstName, lastName, email, phone, address, dob, enrollment);
            studentDAO.create(student);
            response.sendRedirect("StudentServlet?action=list");
        } else if ("update".equals(action)) {
            int id = Integer.parseInt(request.getParameter("id"));
            Student student = studentDAO.read(id);
            student.setFirstName(request.getParameter("firstName"));
            student.setLastName(request.getParameter("lastName"));
            student.setEmail(request.getParameter("email"));
            student.setPhone(request.getParameter("phone"));
            student.setAddress(request.getParameter("address"));
            student.setDateOfBirth(Date.valueOf(request.getParameter("dob")));
            studentDAO.update(student);

            // Update password if provided
            String newPassword = request.getParameter("password");
            if (newPassword != null && !newPassword.isEmpty()) {
                User user = userDAO.read(student.getUserId());
                user.setPassword(newPassword);
                userDAO.update(user);
            }

            response.sendRedirect("StudentServlet?action=list");
        }
    }
}

package servlets;

import dao.StudentDAO;
import dao.StudentDAOImpl;
import dao.UserDAO;
import dao.UserDAOImpl;
import models.Student;
import models.User;

import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServlet;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;

import java.io.IOException;
import java.sql.Date;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.regex.Pattern;
import java.util.List;

public class StudentServlet extends HttpServlet {
    private final StudentDAO studentDAO = new StudentDAOImpl();
    private final UserDAO userDAO = new UserDAOImpl();

    private static final Pattern NAME_PATTERN = Pattern.compile("^[A-Za-z]+$");
    private static final Pattern EMAIL_PATTERN = Pattern.compile("^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$");
    private static final Pattern PHONE_PATTERN = Pattern.compile("^[0-9]{10}$");
    private static final Pattern PASSWORD_PATTERN = Pattern.compile("^[A-Z](?=.*[0-9!@#$%^&*]).{7,}$");

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String action = request.getParameter("action");
        if ("list".equals(action) || action == null) {
            List<Student> students = studentDAO.getAll();
            request.setAttribute("students", students);
            request.getRequestDispatcher("admin/students.jsp").forward(request, response);
        } else if ("edit".equals(action)) {
            int id = Integer.parseInt(request.getParameter("id"));
            Student student = studentDAO.read(id);
            User user = userDAO.read(student.getUserId());
            request.setAttribute("student", student);
            request.setAttribute("user", user);
            request.getRequestDispatcher("admin/editStudent.jsp").forward(request, response);
        } else if ("delete".equals(action)) {
            int id = Integer.parseInt(request.getParameter("id"));
            Student student = studentDAO.read(id);
            if (student != null) {
                userDAO.delete(student.getUserId());
            }
            studentDAO.delete(id);
            response.sendRedirect("StudentServlet?action=list");
        } else if ("add".equals(action)) {
            request.getRequestDispatcher("admin/addStudent.jsp").forward(request, response);
        }
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String action = request.getParameter("action");
        if ("add".equals(action)) {
            Map<String, String> fieldErrors = validateStudentSubmission(request, true);
            if (!fieldErrors.isEmpty()) {
                request.setAttribute("fieldErrors", fieldErrors);
                request.setAttribute("validationError", buildValidationSummary(fieldErrors));
                request.getRequestDispatcher("admin/addStudent.jsp").forward(request, response);
                return;
            }

            // Create user first
            String username = request.getParameter("username");
            String password = request.getParameter("password");
            User user = new User(0, username, password, "student");
            userDAO.create(user);
            // user.getId() is already set by create() method

            // Create student
            String firstName = request.getParameter("firstName");
            String lastName = request.getParameter("lastName");
            String email = request.getParameter("email");
            String phone = request.getParameter("phone");
            String address = request.getParameter("address");
            Date dob = Date.valueOf(request.getParameter("dob"));
            Date enrollment = new Date(System.currentTimeMillis());

            Student student = new Student(0, user.getId(), firstName, lastName, email, phone, address, dob, enrollment);
            studentDAO.create(student);
            response.sendRedirect("StudentServlet?action=list");
        } else if ("update".equals(action)) {
            int id = Integer.parseInt(request.getParameter("id"));
            Student student = studentDAO.read(id);
            User user = userDAO.read(student.getUserId());

            Map<String, String> fieldErrors = validateStudentSubmission(request, false);
            if (!fieldErrors.isEmpty()) {
                request.setAttribute("student", student);
                request.setAttribute("user", user);
                request.setAttribute("fieldErrors", fieldErrors);
                request.setAttribute("validationError", buildValidationSummary(fieldErrors));
                request.getRequestDispatcher("admin/editStudent.jsp").forward(request, response);
                return;
            }

            student.setFirstName(request.getParameter("firstName"));
            student.setLastName(request.getParameter("lastName"));
            student.setEmail(request.getParameter("email"));
            student.setPhone(request.getParameter("phone"));
            student.setAddress(request.getParameter("address"));
            student.setDateOfBirth(Date.valueOf(request.getParameter("dob")));
            studentDAO.update(student);

            // Update password if provided
            String newPassword = request.getParameter("password");
            if (newPassword != null && !newPassword.isEmpty()) {
                user.setPassword(newPassword);
                userDAO.update(user);
            }

            response.sendRedirect("StudentServlet?action=list");
        }
    }

    private Map<String, String> validateStudentSubmission(HttpServletRequest request, boolean requirePassword) {
        Map<String, String> errors = new LinkedHashMap<>();

        String username = request.getParameter("username");
        String password = request.getParameter("password");
        String firstName = request.getParameter("firstName");
        String lastName = request.getParameter("lastName");
        String email = request.getParameter("email");
        String phone = request.getParameter("phone");
        String dob = request.getParameter("dob");

        if (isBlank(username)) {
            setError(errors, "username", "Username is required.");
        } else if (!NAME_PATTERN.matcher(username.trim()).matches()) {
            setError(errors, "username", "Username must contain letters only.");
        }

        if (isBlank(firstName) || !NAME_PATTERN.matcher(firstName.trim()).matches()) {
            setError(errors, "firstName", "First name must contain letters only.");
        }

        if (isBlank(lastName) || !NAME_PATTERN.matcher(lastName.trim()).matches()) {
            setError(errors, "lastName", "Last name must contain letters only.");
        }

        if (isBlank(email) || !EMAIL_PATTERN.matcher(email.trim()).matches()) {
            setError(errors, "email", "Please enter a valid email address.");
        }

        if (isBlank(phone) || !PHONE_PATTERN.matcher(phone.trim()).matches()) {
            setError(errors, "phone", "Phone number must be exactly 10 digits.");
        }

        if (isBlank(dob)) {
            setError(errors, "dob", "Date of birth is required.");
        } else {
            try {
                Date.valueOf(dob.trim());
            } catch (IllegalArgumentException ex) {
                setError(errors, "dob", "Please enter a valid date of birth.");
            }
        }

        if (requirePassword) {
            if (isBlank(password)) {
                setError(errors, "password", "Password is required.");
            } else if (!PASSWORD_PATTERN.matcher(password).matches()) {
                setError(errors, "password", "Password must start with a capital letter and include at least one number or special character.");
            }
        } else if (!isBlank(password) && !PASSWORD_PATTERN.matcher(password.trim()).matches()) {
            setError(errors, "password", "New password must start with a capital letter and include at least one number or special character.");
        }

        return errors;
    }

    private void setError(Map<String, String> errors, String field, String message) {
        errors.put(field, message);
    }

    private String buildValidationSummary(Map<String, String> fieldErrors) {
        return String.join("<br/>", fieldErrors.values());
    }

    private boolean isBlank(String value) {
        return value == null || value.trim().isEmpty();
    }
}

/* ===== Global Styles ===== */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  /* User-provided palette (minor typos corrected: "#55D5D5" and "#0F4E92") */
  --palette-1: #55D5D5; /* teal */
  --palette-2: #41BFFF; /* bright cyan */
  --palette-3: #2CC3D2; /* accent teal */
  --palette-4: #087FD8; /* deep sky blue */
  --palette-5: #0F4E92; /* navy */

  --primary-color: var(--palette-3);
  --primary-dark: var(--palette-4);
  --accent-color: var(--palette-2);
  --secondary-color: #6c757d;
  --success-color: #28a745;
  --danger-color: #dc3545;
  --light-gray: #f8f9fa;
  --medium-gray: #e9ecef;
  --dark-gray: #495057;
  --text-color: #212529;
  --border-color: #dee2e6;
  --shadow: 0 6px 18px rgba(16, 24, 40, 0.08);
  --shadow-lg: 0 12px 32px rgba(16, 24, 40, 0.12);
  --border-radius: 12px;
  --transition: all 0.28s cubic-bezier(.2,.9,.2,1);
}

html, body {
  height: 100%;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  background: linear-gradient(135deg, rgba(13,40,66,0.03) 0%, rgba(44,197,210,0.03) 100%);
  min-height: 100vh;
}

body {
  color: var(--text-color);
  line-height: 1.6;
}

/* ===== Typography ===== */
h1, h2, h3, h4, h5, h6 {
  font-weight: 600;
  color: var(--text-color);
  margin-bottom: 0.5rem;
}

h1 {
  font-size: 2.5rem;
  margin-bottom: 1.5rem;
}

h2 {
  font-size: 1.75rem;
  margin-bottom: 1.25rem;
}

h3 {
  font-size: 1.25rem;
  margin-bottom: 0.75rem;
}

p {
  margin-bottom: 0.75rem;
  color: #666;
}

/* ===== Forms ===== */
.form-container,
.card {
  background: white;
  border-radius: var(--border-radius);
  box-shadow: var(--shadow);
  padding: 2rem;
  margin-bottom: 2rem;
  transition: var(--transition);
}

.form-container:hover,
.card:hover {
  box-shadow: var(--shadow-lg);
}

.form-group {
  margin-bottom: 1.5rem;
}

.form-group label {
  display: block;
  margin-bottom: 0.5rem;
  font-weight: 500;
  color: var(--text-color);
}

input[type="text"],
input[type="email"],
input[type="password"],
input[type="date"],
input[type="number"],
input[type="tel"],
select,
textarea {
  width: 100%;
  padding: 0.75rem;
  border: 2px solid var(--border-color);
  border-radius: 6px;
  font-family: 'Segoe UI', Tahoma, Geneva, sans-serif;
  font-size: 1rem;
  transition: var(--transition);
  background-color: #fff;
}

input[type="text"]:focus,
input[type="email"]:focus,
input[type="password"]:focus,
input[type="date"]:focus,
input[type="number"]:focus,
input[type="tel"]:focus,
select:focus,
textarea:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 3px rgba(0, 123, 255, 0.1);
  background-color: #f0f7ff;
}

input[type="text"]:disabled,
input[type="email"]:disabled,
input[type="password"]:disabled,
input[type="date"]:disabled,
input[type="number"]:disabled,
input[type="tel"]:disabled,
select:disabled,
textarea:disabled {
  background-color: var(--light-gray);
  border-color: var(--medium-gray);
  cursor: not-allowed;
  color: var(--secondary-color);
}

textarea {
  resize: vertical;
  min-height: 100px;
}

/* ===== Buttons ===== */
button,
.btn,
input[type="submit"],
input[type="button"] {
  padding: 0.75rem 1.5rem;
  border: none;
  border-radius: 6px;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
  text-decoration: none;
  display: inline-block;
  text-align: center;
  vertical-align: middle;
}

.btn-primary,
button:not(.btn-secondary, .btn-danger, .btn-success, .btn-secondary),
input[type="submit"]:not([class*="btn-"]),
input[type="button"]:not([class*="btn-"]) {
  background-color: var(--primary-color);
  color: white;
}

.btn-primary:hover,
button:not(.btn-secondary, .btn-danger, .btn-success):hover,
input[type="submit"]:not([class*="btn-"]):hover,
input[type="button"]:not([class*="btn-"]):hover {
  background-color: var(--primary-dark);
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(0, 123, 255, 0.3);
}

.btn-primary:active,
button:active,
input[type="submit"]:active,
input[type="button"]:active {
  transform: translateY(0);
  box-shadow: 0 2px 6px rgba(0, 123, 255, 0.3);
}

.btn-secondary {
  background-color: var(--secondary-color);
  color: white;
}

.btn-secondary:hover {
  background-color: #5a6268;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(108, 117, 125, 0.3);
}

.btn-success {
  background-color: var(--success-color);
  color: white;
}

.btn-success:hover {
  background-color: #218838;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(40, 167, 69, 0.3);
}

.btn-danger {
  background-color: var(--danger-color);
  color: white;
}

.btn-danger:hover {
  background-color: #c82333;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(220, 53, 69, 0.3);
}

.btn-small {
  padding: 0.5rem 1rem;
  font-size: 0.85rem;
}

.btn-block {
  width: 100%;
  display: block;
}

.btn-lg {
  padding: 0.95rem 2rem;
  font-size: 1.05rem;
  border-radius: 12px;
}

/* ===== Tables ===== */
.table-container {
  background: white;
  border-radius: var(--border-radius);
  box-shadow: var(--shadow);
  overflow: hidden;
  transition: var(--transition);
}

.table-container:hover {
  box-shadow: var(--shadow-lg);
}

table {
  width: 100%;
  border-collapse: collapse;
  background: white;
}

thead {
  background: linear-gradient(135deg, var(--primary-color) 0%, var(--primary-dark) 100%);
  color: white;
}

th {
  padding: 1rem;
  text-align: left;
  font-weight: 600;
  font-size: 0.95rem;
  letter-spacing: 0.5px;
}

td {
  padding: 1rem;
  border-bottom: 1px solid var(--border-color);
  vertical-align: middle;
}

tbody tr {
  transition: var(--transition);
}

tbody tr:hover {
  background-color: var(--light-gray);
  transform: scale(1.01);
}

tbody tr:last-child td {
  border-bottom: none;
}

/* ===== Navigation & Layout ===== */
.navbar {
  background: linear-gradient(135deg, var(--palette-4) 0%, var(--palette-5) 100%);
  color: white;
  padding: 0.85rem 1.5rem;
  box-shadow: var(--shadow);
  margin-bottom: 1.75rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.navbar-brand {
  font-size: 1.5rem;
  font-weight: 600;
}

.navbar-menu {
  display: flex;
  gap: 1.5rem;
  align-items: center;
}

.navbar-menu a,
.navbar-menu button {
  color: white;
  text-decoration: none;
  transition: var(--transition);
  padding: 0.5rem 1rem;
  border-radius: 4px;
}

.navbar-menu a:hover,
.navbar-menu button:hover {
  background-color: rgba(255, 255, 255, 0.1);
  transform: translateY(-2px);
}

/* ===== Container ===== */
.container {
  max-width: 1400px;
  margin: 0 auto;
  padding: 2rem;
}

.container-sm {
  max-width: 600px;
  margin: 0 auto;
  padding: 2rem;
}

.container-md {
  max-width: 900px;
  margin: 0 auto;
  padding: 2rem;
}

/* ===== Grid ===== */
.row {
  display: flex;
  flex-wrap: wrap;
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.col {
  flex: 1;
  min-width: 250px;
}

.col-1 { flex: 0 0 8.333%; }
.col-2 { flex: 0 0 16.666%; }
.col-3 { flex: 0 0 25%; }
.col-4 { flex: 0 0 33.333%; }
.col-6 { flex: 0 0 50%; }
.col-8 { flex: 0 0 66.666%; }
.col-9 { flex: 0 0 75%; }
.col-12 { flex: 0 0 100%; }

/* ===== Utility Classes ===== */
.text-center {
  text-align: center;
}

.text-right {
  text-align: right;
}

.text-left {
  text-align: left;
}

.text-muted {
  color: var(--secondary-color);
}

.text-success {
  color: var(--success-color);
}

.text-danger {
  color: var(--danger-color);
}

.text-primary {
  color: var(--primary-color);
}

/* ===== Landing Page ===== */
.landing-page {
  min-height: 100vh;
  background:
    radial-gradient(circle at 20% 20%, rgba(65,191,255,0.12), transparent 28%),
    radial-gradient(circle at 80% 30%, rgba(44,195,210,0.12), transparent 30%),
    linear-gradient(135deg, #f8fbff 0%, #eef6ff 100%);
}

.landing-shell {
  max-width: 1200px;
  margin: 0 auto;
  padding: 1.25rem 1.5rem 3rem;
}

.landing-topbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1rem;
  margin-bottom: 4rem;
}

.landing-brand {
  display: flex;
  align-items: center;
  gap: 0.85rem;
}

.landing-logo {
  width: 44px;
  height: 44px;
  border-radius: 12px;
  display: grid;
  place-items: center;
  background: linear-gradient(135deg, var(--palette-2), var(--palette-5));
  color: white;
  font-weight: 800;
  letter-spacing: 0.6px;
  box-shadow: var(--shadow);
}

.landing-title {
  font-size: 1.2rem;
  font-weight: 800;
  color: #111827;
}

.landing-subtitle {
  font-size: 0.85rem;
  color: #6b7280;
}

.landing-nav-btn {
  text-decoration: none;
  color: #1f2937;
  font-weight: 700;
  padding: 0.75rem 1.15rem;
  border-radius: 12px;
  background: rgba(255,255,255,0.8);
  border: 1px solid rgba(15, 23, 42, 0.08);
  box-shadow: 0 8px 22px rgba(15, 23, 42, 0.05);
}

.landing-grid {
  display: grid;
  grid-template-columns: 1.4fr 0.9fr;
  gap: 1.5rem;
  align-items: stretch;
}

.landing-hero,
.landing-card {
  padding: 2rem;
  border: 1px solid rgba(15, 23, 42, 0.08);
}

.landing-hero h1 {
  font-size: clamp(2.25rem, 5vw, 4.2rem);
  line-height: 1.05;
  margin: 1rem 0 1rem;
  color: #1f2937;
  letter-spacing: -0.03em;
}

.landing-hero p {
  font-size: 1.05rem;
  color: #5f6773;
  max-width: 56ch;
  margin-bottom: 1.5rem;
}

.landing-badge {
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
  padding: 0.45rem 0.8rem;
  border-radius: 999px;
  background: rgba(44, 195, 210, 0.12);
  color: var(--palette-5);
  font-weight: 700;
  font-size: 0.85rem;
}

.landing-actions {
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
}

.landing-card h2 {
  margin-bottom: 1rem;
  color: #1f2937;
}

.landing-points {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 0.8rem;
}

.landing-points li {
  padding: 0.8rem 0.9rem;
  border-radius: 12px;
  background: rgba(255,255,255,0.7);
  border: 1px solid rgba(15, 23, 42, 0.06);
  color: #374151;
  font-weight: 600;
}

.mb-1 { margin-bottom: 0.5rem; }
.mb-2 { margin-bottom: 1rem; }
.mb-3 { margin-bottom: 1.5rem; }
.mb-4 { margin-bottom: 2rem; }
.mb-5 { margin-bottom: 3rem; }

.mt-1 { margin-top: 0.5rem; }
.mt-2 { margin-top: 1rem; }
.mt-3 { margin-top: 1.5rem; }
.mt-4 { margin-top: 2rem; }
.mt-5 { margin-top: 3rem; }

.p-1 { padding: 0.5rem; }
.p-2 { padding: 1rem; }
.p-3 { padding: 1.5rem; }
.p-4 { padding: 2rem; }

.ml-auto {
  margin-left: auto;
}

.mr-auto {
  margin-right: auto;
}

.d-flex {
  display: flex;
}

.align-items-center {
  align-items: center;
}

.justify-content-between {
  justify-content: space-between;
}

.justify-content-center {
  justify-content: center;
}

.gap-1 { gap: 0.5rem; }
.gap-2 { gap: 1rem; }
.gap-3 { gap: 1.5rem; }

/* ===== Alerts & Messages ===== */
.alert {
  padding: 1rem;
  margin-bottom: 1rem;
  border-radius: var(--border-radius);
  border-left: 4px solid;
  animation: slideInDown 0.3s ease-in-out;
}

.alert-success {
  background-color: #d4edda;
  color: #155724;
  border-color: #28a745;
}

.alert-danger {
  background-color: #f8d7da;
  color: #721c24;
  border-color: #dc3545;
}

.alert-warning {
  background-color: #fff3cd;
  color: #856404;
  border-color: #ffc107;
}

.alert-info {
  background-color: #d1ecf1;
  color: #0c5460;
  border-color: #17a2b8;
}

.error {
  color: var(--danger-color);
  margin-top: 0.5rem;
  font-weight: 500;
}

/* ===== Header with Buttons ===== */
.header-buttons {
  display: flex;
  gap: 1rem;
  margin-bottom: 2rem;
  flex-wrap: wrap;
}

.header-buttons .btn {
  flex-shrink: 0;
}

/* ===== Logout Button ===== */
.logout-btn,
.back-btn {
  padding: 0.75rem 1.5rem;
  border-radius: 6px;
  text-decoration: none;
  font-weight: 600;
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  transition: var(--transition);
}

.logout-btn {
  background-color: var(--danger-color);
  color: white;
}

.logout-btn:hover {
  background-color: #c82333;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(220, 53, 69, 0.3);
}

.back-btn {
  background-color: var(--secondary-color);
  color: white;
}

.back-btn:hover {
  background-color: #5a6268;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(108, 117, 125, 0.3);
}

/* ===== Action Buttons ===== */
.action-btn {
  display: inline-block;
  padding: 0.5rem 0.75rem;
  border-radius: 4px;
  color: white;
  text-decoration: none;
  margin-right: 0.5rem;
  margin-bottom: 0.5rem;
  font-size: 0.85rem;
  font-weight: 600;
  transition: var(--transition);
  cursor: pointer;
}

.edit-btn {
  background-color: var(--primary-color);
}

.edit-btn:hover {
  background-color: var(--primary-dark);
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(0, 123, 255, 0.3);
}

.delete-btn {
  background-color: var(--danger-color);
}

.delete-btn:hover {
  background-color: #c82333;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(220, 53, 69, 0.3);
}

.view-btn {
  background-color: var(--primary-color);
}

.view-btn:hover {
  background-color: var(--primary-dark);
  transform: translateY(-2px);
}

/* ===== Menu/Dashboard Cards ===== */
.menu {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
}

/* ===== Sidebar Layout (Admin panel reference) ===== */
.app-shell {
  display: grid;
  grid-template-columns: 260px 1fr;
  gap: 0;
  min-height: calc(100vh - 40px);
}

.sidebar {
  background: linear-gradient(180deg, var(--palette-5) 0%, var(--palette-4) 100%);
  color: white;
  padding: 1.5rem 1rem;
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
}

.sidebar .brand {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.sidebar .brand img { width: 44px; height: 44px; border-radius: 6px; object-fit:cover; }
.sidebar .brand h3 { font-size: 1.05rem; margin: 0; font-weight: 800; letter-spacing: 0.2px; }
.sidebar .brand small { color: rgba(255,255,255,0.85); }

.sidebar .profile {
  display: flex;
  gap: 0.75rem;
  align-items: center;
  padding: 0.6rem;
  border-radius: 10px;
  background: linear-gradient(90deg, rgba(255,255,255,0.03), rgba(255,255,255,0.01));
  box-shadow: inset 0 -1px 0 rgba(255,255,255,0.02);
}
.sidebar .profile img { width: 48px; height: 48px; border-radius: 50%; object-fit:cover; }
.sidebar .profile .name { font-weight: 700; color: #fff; }
.sidebar .profile div { line-height: 1; }
.sidebar .profile div div:last-child { font-size: 0.82rem; opacity: 0.9; }

.sidebar-nav { display: flex; flex-direction: column; gap: 0.35rem; margin-top: 0.8rem; }
.sidebar-nav a {
  color: rgba(255,255,255,0.95);
  text-decoration: none;
  padding: 0.65rem 0.9rem;
  border-radius: 10px;
  display: flex;
  gap: 0.8rem;
  align-items: center;
  font-weight: 600;
  transition: background 180ms var(--transition), transform 180ms var(--transition);
}
.sidebar-nav a:hover {
  background: linear-gradient(90deg, rgba(255,255,255,0.06), rgba(255,255,255,0.03));
  transform: translateX(6px);
}
.sidebar-nav .nav-icon { display:none; }
.sidebar-nav a .label { flex:1; }

/* replace emoji icons with subtle dot via pseudo-element to avoid encoding issues */
.sidebar-nav a::before {
  content: '';
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: rgba(255,255,255,0.18);
  display: inline-block;
  margin-right: 0.7rem;
  box-shadow: 0 2px 6px rgba(2,6,23,0.12);
}
.sidebar-nav a:hover::before { background: var(--accent-color); box-shadow: 0 6px 12px rgba(8,127,216,0.16); }
.sidebar-nav a.active::before { background: linear-gradient(180deg, var(--accent-color), var(--primary-dark)); box-shadow: 0 8px 18px rgba(2,6,23,0.18); }

/* make labels bold and stylish */
.sidebar-nav a .label {
  font-weight: 800;
  font-size: 0.98rem;
  letter-spacing: 0.2px;
  color: rgba(255,255,255,0.98);
}
.sidebar-nav a.active {
  background: linear-gradient(90deg, rgba(255,255,255,0.12), rgba(255,255,255,0.06));
  box-shadow: 0 8px 18px rgba(2,6,23,0.18);
  transform: none;
}
.sidebar-nav a.active::after {
  content: '';
  width: 4px;
  height: 36px;
  background: linear-gradient(180deg, var(--accent-color), var(--primary-dark));
  border-radius: 4px;
  margin-left: 8px;
}

/* make text clearer */
.sidebar-nav a span { color: rgba(255,255,255,0.98); }

/* small separators */
.sidebar .sep { height:1px; background: rgba(255,255,255,0.04); margin: 0.5rem 0; border-radius:2px; }

.main-area { padding: 1.5rem; background: linear-gradient(180deg, rgba(255,255,255,0.02), rgba(255,255,255,0.00)); }
.content-header { display:flex; justify-content: space-between; align-items: center; gap: 1rem; margin-bottom: 1rem; }
.content-header .page-title { display:flex; gap:0.6rem; align-items:center; }
.breadcrumb { color: #7f9bb3; font-size: 0.95rem; }

/* Table / list header style to reflect reference */
.panel { background: white; border-radius: 12px; box-shadow: var(--shadow); padding: 1rem; }
.panel .panel-title { font-weight: 700; font-size: 1.2rem; }

@media (max-width: 900px) {
  .app-shell { grid-template-columns: 1fr; }
  .sidebar { flex-direction: row; align-items:center; gap: 0.8rem; padding: 0.8rem; }
  .sidebar-nav { display:none; }
}

.menu-card,
.menu-button {
  background: white;
  padding: 1.5rem;
  border-radius: var(--border-radius);
  text-align: center;
  text-decoration: none;
  color: white;
  font-weight: 600;
  font-size: 1rem;
  transition: var(--transition);
  border: none;
  cursor: pointer;
  box-shadow: var(--shadow);
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 120px;
}

.menu-button {
  background: linear-gradient(135deg, var(--palette-2) 0%, var(--palette-3) 40%, var(--palette-4) 100%);
  color: white;
  flex-direction: column;
}

.menu-button:hover,
.menu-card:hover {
  transform: translateY(-6px) scale(1.02);
  box-shadow: var(--shadow-lg);
}

/* Animated micro-interactions */
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(12px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes floatUp {
  0% { transform: translateY(0); }
  50% { transform: translateY(-6px); }
  100% { transform: translateY(0); }
}

.fade-in { animation: fadeInUp 480ms ease forwards; }
.fade-in-up { animation: fadeInUp 520ms cubic-bezier(.2,.9,.2,1) forwards; }
.menu-button { transition: transform 220ms var(--transition), box-shadow 220ms var(--transition); }
.menu-button .menu-icon { font-size: 2.2rem; margin-bottom: 0.5rem; }
.menu-button .menu-label { font-size: 0.95rem; }

.dashboard-hero {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1.5rem;
  margin-bottom: 1.5rem;
}
.dashboard-hero .hero-text { max-width: 65%; }
.dashboard-hero .hero-text h1 { font-size: 2rem; margin-bottom: 0.25rem; }
.dashboard-hero .hero-actions { display: flex; gap: 0.6rem; flex-wrap: wrap; }
.dashboard-hero .hero-actions .btn { padding: 0.6rem 1rem; border-radius: 10px; }

.stat-card { text-align: center; }
.animated-grid { animation: fadeInUp 520ms ease 160ms both; }

.menu-button.secondary {
  background: linear-gradient(135deg, var(--secondary-color) 0%, #5a6268 100%);
}

.menu-button.secondary:hover {
  background: linear-gradient(135deg, #5a6268 0%, #484d52 100%);
}

.menu-button.success {
  background: linear-gradient(135deg, var(--success-color) 0%, #218838 100%);
}

.menu-button.success:hover {
  background: linear-gradient(135deg, #218838 0%, #1e7e34 100%);
}

/* ===== Responsive Design ===== */
@media (max-width: 768px) {
  h1 {
    font-size: 2rem;
  }

  h2 {
    font-size: 1.5rem;
  }

  .container,
  .container-sm,
  .container-md {
    padding: 1rem;
  }

  .menu {
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: 1rem;
  }

  .header-buttons {
    flex-direction: column;
  }

  .header-buttons .btn {
    width: 100%;
  }

  .col-6 {
    flex: 0 0 100%;
  }

  table {
    font-size: 0.9rem;
  }

  th, td {
    padding: 0.75rem;
  }

  .action-btn {
    padding: 0.4rem 0.6rem;
    font-size: 0.75rem;
    display: block;
    margin-bottom: 0.25rem;
    width: 100%;
    text-align: center;
  }

  .landing-topbar {
    flex-direction: column;
    align-items: flex-start;
    margin-bottom: 2rem;
  }

  .landing-grid {
    grid-template-columns: 1fr;
  }

  .landing-hero,
  .landing-card {
    padding: 1.5rem;
  }
}

@media (max-width: 480px) {
  .navbar {
    flex-direction: column;
    gap: 1rem;
  }

  .navbar-menu {
    width: 100%;
    justify-content: center;
    flex-wrap: wrap;
  }

  .form-container,
  .card {
    padding: 1.5rem;
  }

  button,
  .btn,
  input[type="submit"],
  input[type="button"] {
    padding: 0.6rem 1.2rem;
  }

  .menu {
    grid-template-columns: 1fr;
  }

  .menu-button,
  .menu-card {
    min-height: 100px;
    font-size: 0.9rem;
  }
}

/* ===== Global Styles ===== */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  /* User-provided palette (minor typos corrected: "#55D5D5" and "#0F4E92") */
  --palette-1: #55D5D5; /* teal */
  --palette-2: #41BFFF; /* bright cyan */
  --palette-3: #2CC3D2; /* accent teal */
  --palette-4: #087FD8; /* deep sky blue */
  --palette-5: #0F4E92; /* navy */

  --primary-color: var(--palette-3);
  --primary-dark: var(--palette-4);
  --accent-color: var(--palette-2);
  --secondary-color: #6c757d;
  --success-color: #28a745;
  --danger-color: #dc3545;
  --light-gray: #f8f9fa;
  --medium-gray: #e9ecef;
  --dark-gray: #495057;
  --text-color: #212529;
  --border-color: #dee2e6;
  --shadow: 0 6px 18px rgba(16, 24, 40, 0.08);
  --shadow-lg: 0 12px 32px rgba(16, 24, 40, 0.12);
  --border-radius: 12px;
  --transition: all 0.28s cubic-bezier(.2,.9,.2,1);
}

html, body {
  height: 100%;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  background: linear-gradient(135deg, rgba(13,40,66,0.03) 0%, rgba(44,197,210,0.03) 100%);
  min-height: 100vh;
}

body {
  color: var(--text-color);
  line-height: 1.6;
}

/* ===== Typography ===== */
h1, h2, h3, h4, h5, h6 {
  font-weight: 600;
  color: var(--text-color);
  margin-bottom: 0.5rem;
}

h1 {
  font-size: 2.5rem;
  margin-bottom: 1.5rem;
}

h2 {
  font-size: 1.75rem;
  margin-bottom: 1.25rem;
}

h3 {
  font-size: 1.25rem;
  margin-bottom: 0.75rem;
}

p {
  margin-bottom: 0.75rem;
  color: #666;
}

/* ===== Forms ===== */
.form-container,
.card {
  background: white;
  border-radius: var(--border-radius);
  box-shadow: var(--shadow);
  padding: 2rem;
  margin-bottom: 2rem;
  transition: var(--transition);
}

.form-container:hover,
.card:hover {
  box-shadow: var(--shadow-lg);
}

.form-group {
  margin-bottom: 1.5rem;
}

.form-group label {
  display: block;
  margin-bottom: 0.5rem;
  font-weight: 500;
  color: var(--text-color);
}

input[type="text"],
input[type="email"],
input[type="password"],
input[type="date"],
input[type="number"],
input[type="tel"],
select,
textarea {
  width: 100%;
  padding: 0.75rem;
  border: 2px solid var(--border-color);
  border-radius: 6px;
  font-family: 'Segoe UI', Tahoma, Geneva, sans-serif;
  font-size: 1rem;
  transition: var(--transition);
  background-color: #fff;
}

input[type="text"]:focus,
input[type="email"]:focus,
input[type="password"]:focus,
input[type="date"]:focus,
input[type="number"]:focus,
input[type="tel"]:focus,
select:focus,
textarea:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 0 3px rgba(0, 123, 255, 0.1);
  background-color: #f0f7ff;
}

input[type="text"]:disabled,
input[type="email"]:disabled,
input[type="password"]:disabled,
input[type="date"]:disabled,
input[type="number"]:disabled,
input[type="tel"]:disabled,
select:disabled,
textarea:disabled {
  background-color: var(--light-gray);
  border-color: var(--medium-gray);
  cursor: not-allowed;
  color: var(--secondary-color);
}

textarea {
  resize: vertical;
  min-height: 100px;
}

.input-invalid {
  border-color: var(--danger-color) !important;
  box-shadow: 0 0 0 3px rgba(220, 53, 69, 0.12) !important;
  background-color: #fff7f7 !important;
}

/* Validation error text with smooth appearance */
/* stronger selector and !important to ensure the error text uses the danger color
   even if other styles (page-level or browser defaults) interfere */
.login-container .field-error,
.field-error {
  /* always reserve space under the input so layout doesn't jump */
  display: block;
  margin-top: 0.45rem;
  color: var(--danger-color) !important;
  font-size: 0.9rem;
  font-weight: 500;
  min-height: 1.1rem;
  opacity: 0;
  transform: translateY(-6px);
  transition: opacity 180ms ease, transform 180ms ease;
  visibility: hidden;
}

/* show when there is text (set by server or client JS) */
.field-error:not(:empty) {
  opacity: 1;
  transform: translateY(0);
  visibility: visible;
}

/* strong show for input elements marked invalid by JS/CSS */
input.input-invalid + .field-error,
textarea.input-invalid + .field-error,
select.input-invalid + .field-error {
  opacity: 1 !important;
  transform: translateY(0) !important;
  visibility: visible !important;
}

/* make the small error text align and stand out */
.form-group .field-error {
  margin-left: 2px;
}

/* Accessibility: focus invalid inputs */
input.input-invalid:focus, textarea.input-invalid:focus, select.input-invalid:focus {
  outline: none;
  box-shadow: 0 0 0 4px rgba(220,53,69,0.08);
}

/* ===== Buttons ===== */
button,
.btn,
input[type="submit"],
input[type="button"] {
  padding: 0.75rem 1.5rem;
  border: none;
  border-radius: 6px;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: var(--transition);
  text-decoration: none;
  display: inline-block;
  text-align: center;
  vertical-align: middle;
}

.btn-primary,
button:not(.btn-secondary, .btn-danger, .btn-success, .btn-secondary),
input[type="submit"]:not([class*="btn-"]),
input[type="button"]:not([class*="btn-"]) {
  background-color: var(--primary-color);
  color: white;
}

.btn-primary:hover,
button:not(.btn-secondary, .btn-danger, .btn-success):hover,
input[type="submit"]:not([class*="btn-"]):hover,
input[type="button"]:not([class*="btn-"]):hover {
  background-color: var(--primary-dark);
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(0, 123, 255, 0.3);
}

.btn-primary:active,
button:active,
input[type="submit"]:active,
input[type="button"]:active {
  transform: translateY(0);
  box-shadow: 0 2px 6px rgba(0, 123, 255, 0.3);
}

.btn-secondary {
  background-color: var(--secondary-color);
  color: white;
}

.btn-secondary:hover {
  background-color: #5a6268;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(108, 117, 125, 0.3);
}

.btn-success {
  background-color: var(--success-color);
  color: white;
}

.btn-success:hover {
  background-color: #218838;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(40, 167, 69, 0.3);
}

.btn-danger {
  background-color: var(--danger-color);
  color: white;
}

.btn-danger:hover {
  background-color: #c82333;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(220, 53, 69, 0.3);
}

.btn-small {
  padding: 0.5rem 1rem;
  font-size: 0.85rem;
}

.btn-block {
  width: 100%;
  display: block;
}

.btn-lg {
  padding: 0.95rem 2rem;
  font-size: 1.05rem;
  border-radius: 12px;
}

/* ===== Tables ===== */
.table-container {
  background: white;
  border-radius: var(--border-radius);
  box-shadow: var(--shadow);
  overflow: hidden;
  transition: var(--transition);
}

.table-container:hover {
  box-shadow: var(--shadow-lg);
}

table {
  width: 100%;
  border-collapse: collapse;
  background: white;
}

thead {
  background: linear-gradient(135deg, var(--primary-color) 0%, var(--primary-dark) 100%);
  color: white;
}

th {
  padding: 1rem;
  text-align: left;
  font-weight: 600;
  font-size: 0.95rem;
  letter-spacing: 0.5px;
}

td {
  padding: 1rem;
  border-bottom: 1px solid var(--border-color);
  vertical-align: middle;
}

tbody tr {
  transition: var(--transition);
}

tbody tr:hover {
  background-color: var(--light-gray);
  transform: scale(1.01);
}

tbody tr:last-child td {
  border-bottom: none;
}

/* ===== Navigation & Layout ===== */
.navbar {
  background: linear-gradient(135deg, var(--palette-4) 0%, var(--palette-5) 100%);
  color: white;
  padding: 0.85rem 1.5rem;
  box-shadow: var(--shadow);
  margin-bottom: 1.75rem;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.navbar-brand {
  font-size: 1.5rem;
  font-weight: 600;
}

.navbar-menu {
  display: flex;
  gap: 1.5rem;
  align-items: center;
}

.navbar-menu a,
.navbar-menu button {
  color: white;
  text-decoration: none;
  transition: var(--transition);
  padding: 0.5rem 1rem;
  border-radius: 4px;
}

.navbar-menu a:hover,
.navbar-menu button:hover {
  background-color: rgba(255, 255, 255, 0.1);
  transform: translateY(-2px);
}

/* ===== Container ===== */
.container {
  max-width: 1400px;
  margin: 0 auto;
  padding: 2rem;
}

.container-sm {
  max-width: 600px;
  margin: 0 auto;
  padding: 2rem;
}

.container-md {
  max-width: 900px;
  margin: 0 auto;
  padding: 2rem;
}

/* ===== Grid ===== */
.row {
  display: flex;
  flex-wrap: wrap;
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.col {
  flex: 1;
  min-width: 250px;
}

.col-1 { flex: 0 0 8.333%; }
.col-2 { flex: 0 0 16.666%; }
.col-3 { flex: 0 0 25%; }
.col-4 { flex: 0 0 33.333%; }
.col-6 { flex: 0 0 50%; }
.col-8 { flex: 0 0 66.666%; }
.col-9 { flex: 0 0 75%; }
.col-12 { flex: 0 0 100%; }

/* ===== Utility Classes ===== */
.text-center {
  text-align: center;
}

.text-right {
  text-align: right;
}

.text-left {
  text-align: left;
}

.text-muted {
  color: var(--secondary-color);
}

.text-success {
  color: var(--success-color);
}

.text-danger {
  color: var(--danger-color);
}

.text-primary {
  color: var(--primary-color);
}

/* ===== Landing Page ===== */
.landing-page {
  min-height: 100vh;
  background:
    radial-gradient(circle at 20% 20%, rgba(65,191,255,0.12), transparent 28%),
    radial-gradient(circle at 80% 30%, rgba(44,195,210,0.12), transparent 30%),
    linear-gradient(135deg, #f8fbff 0%, #eef6ff 100%);
}

.landing-shell {
  max-width: 1200px;
  margin: 0 auto;
  padding: 1.25rem 1.5rem 3rem;
}

.landing-topbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1rem;
  margin-bottom: 4rem;
}

.landing-brand {
  display: flex;
  align-items: center;
  gap: 0.85rem;
}

.landing-logo {
  width: 44px;
  height: 44px;
  border-radius: 12px;
  display: grid;
  place-items: center;
  background: linear-gradient(135deg, var(--palette-2), var(--palette-5));
  color: white;
  font-weight: 800;
  letter-spacing: 0.6px;
  box-shadow: var(--shadow);
}

.landing-title {
  font-size: 1.2rem;
  font-weight: 800;
  color: #111827;
}

.landing-subtitle {
  font-size: 0.85rem;
  color: #6b7280;
}

.landing-nav-btn {
  text-decoration: none;
  color: #1f2937;
  font-weight: 700;
  padding: 0.75rem 1.15rem;
  border-radius: 12px;
  background: rgba(255,255,255,0.8);
  border: 1px solid rgba(15, 23, 42, 0.08);
  box-shadow: 0 8px 22px rgba(15, 23, 42, 0.05);
}

.landing-grid {
  display: grid;
  grid-template-columns: 1.4fr 0.9fr;
  gap: 1.5rem;
  align-items: stretch;
}

.landing-hero,
.landing-card {
  padding: 2rem;
  border: 1px solid rgba(15, 23, 42, 0.08);
}

.landing-hero h1 {
  font-size: clamp(2.25rem, 5vw, 4.2rem);
  line-height: 1.05;
  margin: 1rem 0 1rem;
  color: #1f2937;
  letter-spacing: -0.03em;
}

.landing-hero p {
  font-size: 1.05rem;
  color: #5f6773;
  max-width: 56ch;
  margin-bottom: 1.5rem;
}

.landing-badge {
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
  padding: 0.45rem 0.8rem;
  border-radius: 999px;
  background: rgba(44, 195, 210, 0.12);
  color: var(--palette-5);
  font-weight: 700;
  font-size: 0.85rem;
}

.landing-actions {
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
}

.landing-card h2 {
  margin-bottom: 1rem;
  color: #1f2937;
}

.landing-points {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 0.8rem;
}

.landing-points li {
  padding: 0.8rem 0.9rem;
  border-radius: 12px;
  background: rgba(255,255,255,0.7);
  border: 1px solid rgba(15, 23, 42, 0.06);
  color: #374151;
  font-weight: 600;
}

.mb-1 { margin-bottom: 0.5rem; }
.mb-2 { margin-bottom: 1rem; }
.mb-3 { margin-bottom: 1.5rem; }
.mb-4 { margin-bottom: 2rem; }
.mb-5 { margin-bottom: 3rem; }

.mt-1 { margin-top: 0.5rem; }
.mt-2 { margin-top: 1rem; }
.mt-3 { margin-top: 1.5rem; }
.mt-4 { margin-top: 2rem; }
.mt-5 { margin-top: 3rem; }

.p-1 { padding: 0.5rem; }
.p-2 { padding: 1rem; }
.p-3 { padding: 1.5rem; }
.p-4 { padding: 2rem; }

.ml-auto {
  margin-left: auto;
}

.mr-auto {
  margin-right: auto;
}

.d-flex {
  display: flex;
}

.align-items-center {
  align-items: center;
}

.justify-content-between {
  justify-content: space-between;
}

.justify-content-center {
  justify-content: center;
}

.gap-1 { gap: 0.5rem; }
.gap-2 { gap: 1rem; }
.gap-3 { gap: 1.5rem; }

/* ===== Alerts & Messages ===== */
.alert {
  padding: 1rem;
  margin-bottom: 1rem;
  border-radius: var(--border-radius);
  border-left: 4px solid;
  animation: slideInDown 0.3s ease-in-out;
}

.alert-success {
  background-color: #d4edda;
  color: #155724;
  border-color: #28a745;
}

.alert-danger {
  background-color: #f8d7da;
  color: #721c24;
  border-color: #dc3545;
}

.alert-warning {
  background-color: #fff3cd;
  color: #856404;
  border-color: #ffc107;
}

.alert-info {
  background-color: #d1ecf1;
  color: #0c5460;
  border-color: #17a2b8;
}

.error {
  color: var(--danger-color);
  margin-top: 0.5rem;
  font-weight: 500;
}

/* ===== Header with Buttons ===== */
.header-buttons {
  display: flex;
  gap: 1rem;
  margin-bottom: 2rem;
  flex-wrap: wrap;
}

.header-buttons .btn {
  flex-shrink: 0;
}

/* ===== Logout Button ===== */
.logout-btn,
.back-btn {
  padding: 0.75rem 1.5rem;
  border-radius: 6px;
  text-decoration: none;
  font-weight: 600;
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  transition: var(--transition);
}

.logout-btn {
  background-color: var(--danger-color);
  color: white;
}

.logout-btn:hover {
  background-color: #c82333;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(220, 53, 69, 0.3);
}

.back-btn {
  background-color: var(--secondary-color);
  color: white;
}

.back-btn:hover {
  background-color: #5a6268;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(108, 117, 125, 0.3);
}

/* ===== Action Buttons ===== */
.action-btn {
  display: inline-block;
  padding: 0.5rem 0.75rem;
  border-radius: 4px;
  color: white;
  text-decoration: none;
  margin-right: 0.5rem;
  margin-bottom: 0.5rem;
  font-size: 0.85rem;
  font-weight: 600;
  transition: var(--transition);
  cursor: pointer;
}

.edit-btn {
  background-color: var(--primary-color);
}

.edit-btn:hover {
  background-color: var(--primary-dark);
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(0, 123, 255, 0.3);
}

.delete-btn {
  background-color: var(--danger-color);
}

.delete-btn:hover {
  background-color: #c82333;
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(220, 53, 69, 0.3);
}

.view-btn {
  background-color: var(--primary-color);
}

.view-btn:hover {
  background-color: var(--primary-dark);
  transform: translateY(-2px);
}

/* ===== Menu/Dashboard Cards ===== */
.menu {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
}

/* ===== Sidebar Layout (Admin panel reference) ===== */
.app-shell {
  display: grid;
  grid-template-columns: 260px 1fr;
  gap: 0;
  min-height: calc(100vh - 40px);
}

.sidebar {
  background: linear-gradient(180deg, var(--palette-5) 0%, var(--palette-4) 100%);
  color: white;
  padding: 1.5rem 1rem;
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
}

.sidebar .brand {
  display: flex;
  align-items: center;
  gap: 0.75rem;
}

.sidebar .brand img { width: 44px; height: 44px; border-radius: 6px; object-fit:cover; }
.sidebar .brand h3 { font-size: 1.05rem; margin: 0; font-weight: 800; letter-spacing: 0.2px; }
.sidebar .brand small { color: rgba(255,255,255,0.85); }

.sidebar .profile {
  display: flex;
  gap: 0.75rem;
  align-items: center;
  padding: 0.6rem;
  border-radius: 10px;
  background: linear-gradient(90deg, rgba(255,255,255,0.03), rgba(255,255,255,0.01));
  box-shadow: inset 0 -1px 0 rgba(255,255,255,0.02);
}
.sidebar .profile img { width: 48px; height: 48px; border-radius: 50%; object-fit:cover; }
.sidebar .profile .name { font-weight: 700; color: #fff; }
.sidebar .profile div { line-height: 1; }
.sidebar .profile div div:last-child { font-size: 0.82rem; opacity: 0.9; }

.sidebar-nav { display: flex; flex-direction: column; gap: 0.35rem; margin-top: 0.8rem; }
.sidebar-nav a {
  color: rgba(255,255,255,0.95);
  text-decoration: none;
  padding: 0.65rem 0.9rem;
  border-radius: 10px;
  display: flex;
  gap: 0.8rem;
  align-items: center;
  font-weight: 600;
  transition: background 180ms var(--transition), transform 180ms var(--transition);
}
.sidebar-nav a:hover {
  background: linear-gradient(90deg, rgba(255,255,255,0.06), rgba(255,255,255,0.03));
  transform: translateX(6px);
}
.sidebar-nav .nav-icon { display:none; }
.sidebar-nav a .label { flex:1; }

/* replace emoji icons with subtle dot via pseudo-element to avoid encoding issues */
.sidebar-nav a::before {
  content: '';
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: rgba(255,255,255,0.18);
  display: inline-block;
  margin-right: 0.7rem;
  box-shadow: 0 2px 6px rgba(2,6,23,0.12);
}
.sidebar-nav a:hover::before { background: var(--accent-color); box-shadow: 0 6px 12px rgba(8,127,216,0.16); }
.sidebar-nav a.active::before { background: linear-gradient(180deg, var(--accent-color), var(--primary-dark)); box-shadow: 0 8px 18px rgba(2,6,23,0.18); }

/* make labels bold and stylish */
.sidebar-nav a .label {
  font-weight: 800;
  font-size: 0.98rem;
  letter-spacing: 0.2px;
  color: rgba(255,255,255,0.98);
}
.sidebar-nav a.active {
  background: linear-gradient(90deg, rgba(255,255,255,0.12), rgba(255,255,255,0.06));
  box-shadow: 0 8px 18px rgba(2,6,23,0.18);
  transform: none;
}
.sidebar-nav a.active::after {
  content: '';
  width: 4px;
  height: 36px;
  background: linear-gradient(180deg, var(--accent-color), var(--primary-dark));
  border-radius: 4px;
  margin-left: 8px;
}

/* make text clearer */
.sidebar-nav a span { color: rgba(255,255,255,0.98); }

/* small separators */
.sidebar .sep { height:1px; background: rgba(255,255,255,0.04); margin: 0.5rem 0; border-radius:2px; }

.main-area { padding: 1.5rem; background: linear-gradient(180deg, rgba(255,255,255,0.02), rgba(255,255,255,0.00)); }
.content-header { display:flex; justify-content: space-between; align-items: center; gap: 1rem; margin-bottom: 1rem; }
.content-header .page-title { display:flex; gap:0.6rem; align-items:center; }
.breadcrumb { color: #7f9bb3; font-size: 0.95rem; }

/* Table / list header style to reflect reference */
.panel { background: white; border-radius: 12px; box-shadow: var(--shadow); padding: 1rem; }
.panel .panel-title { font-weight: 700; font-size: 1.2rem; }

@media (max-width: 900px) {
  .app-shell { grid-template-columns: 1fr; }
  .sidebar { flex-direction: row; align-items:center; gap: 0.8rem; padding: 0.8rem; }
  .sidebar-nav { display:none; }
}

.menu-card,
.menu-button {
  background: white;
  padding: 1.5rem;
  border-radius: var(--border-radius);
  text-align: center;
  text-decoration: none;
  color: white;
  font-weight: 600;
  font-size: 1rem;
  transition: var(--transition);
  border: none;
  cursor: pointer;
  box-shadow: var(--shadow);
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 120px;
}

.menu-button {
  background: linear-gradient(135deg, var(--palette-2) 0%, var(--palette-3) 40%, var(--palette-4) 100%);
  color: white;
  flex-direction: column;
}

.menu-button:hover,
.menu-card:hover {
  transform: translateY(-6px) scale(1.02);
  box-shadow: var(--shadow-lg);
}

/* Animated micro-interactions */
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(12px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes floatUp {
  0% { transform: translateY(0); }
  50% { transform: translateY(-6px); }
  100% { transform: translateY(0); }
}

.fade-in { animation: fadeInUp 480ms ease forwards; }
.fade-in-up { animation: fadeInUp 520ms cubic-bezier(.2,.9,.2,1) forwards; }
.menu-button { transition: transform 220ms var(--transition), box-shadow 220ms var(--transition); }
.menu-button .menu-icon { font-size: 2.2rem; margin-bottom: 0.5rem; }
.menu-button .menu-label { font-size: 0.95rem; }

.dashboard-hero {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1.5rem;
  margin-bottom: 1.5rem;
}
.dashboard-hero .hero-text { max-width: 65%; }
.dashboard-hero .hero-text h1 { font-size: 2rem; margin-bottom: 0.25rem; }
.dashboard-hero .hero-actions { display: flex; gap: 0.6rem; flex-wrap: wrap; }
.dashboard-hero .hero-actions .btn { padding: 0.6rem 1rem; border-radius: 10px; }

.stat-card { text-align: center; }
.animated-grid { animation: fadeInUp 520ms ease 160ms both; }

.menu-button.secondary {
  background: linear-gradient(135deg, var(--secondary-color) 0%, #5a6268 100%);
}

.menu-button.secondary:hover {
  background: linear-gradient(135deg, #5a6268 0%, #484d52 100%);
}

.menu-button.success {
  background: linear-gradient(135deg, var(--success-color) 0%, #218838 100%);
}

.menu-button.success:hover {
  background: linear-gradient(135deg, #218838 0%, #1e7e34 100%);
}

/* ===== Responsive Design ===== */
@media (max-width: 768px) {
  h1 {
    font-size: 2rem;
  }

  h2 {
    font-size: 1.5rem;
  }

  .container,
  .container-sm,
  .container-md {
    padding: 1rem;
  }

  .menu {
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: 1rem;
  }

  .header-buttons {
    flex-direction: column;
  }

  .header-buttons .btn {
    width: 100%;
  }

  .col-6 {
    flex: 0 0 100%;
  }

  table {
    font-size: 0.9rem;
  }

  th, td {
    padding: 0.75rem;
  }

  .action-btn {
    padding: 0.4rem 0.6rem;
    font-size: 0.75rem;
    display: block;
    margin-bottom: 0.25rem;
    width: 100%;
    text-align: center;
  }

  .landing-topbar {
    flex-direction: column;
    align-items: flex-start;
    margin-bottom: 2rem;
  }

  .landing-grid {
    grid-template-columns: 1fr;
  }

  .landing-hero,
  .landing-card {
    padding: 1.5rem;
  }
}

@media (max-width: 480px) {
  .navbar {
    flex-direction: column;
    gap: 1rem;
  }

  .navbar-menu {
    width: 100%;
    justify-content: center;
    flex-wrap: wrap;
  }

  .form-container,
  .card {
    padding: 1.5rem;
  }

  button,
  .btn,
  input[type="submit"],
  input[type="button"] {
    padding: 0.6rem 1.2rem;
  }

  .menu {
    grid-template-columns: 1fr;
  }

  .menu-button,
  .menu-card {
    min-height: 100px;
    font-size: 0.9rem;
  }
}

function isBlank(value) {
	return value === null || value === undefined || String(value).trim() === '';
}

function setFieldError(inputId, message) {
	const input = document.getElementById(inputId);
	const error = document.getElementById(inputId + 'Error');
	if (input) input.classList.add('input-invalid');
	if (error) error.textContent = message || '';
}

function clearFieldError(inputId) {
	const input = document.getElementById(inputId);
	const error = document.getElementById(inputId + 'Error');
	if (input) input.classList.remove('input-invalid');
	if (error) error.textContent = '';
}

function clearStudentErrors(fieldIds) {
	fieldIds.forEach(clearFieldError);
}

function validateLettersOnly(value) {
	return /^[A-Za-z]+$/.test(String(value).trim());
}

function validateEmail(value) {
	return /^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$/.test(String(value).trim());
}

function validatePhone(value) {
	return /^[0-9]{10}$/.test(String(value).trim());
}

function validatePassword(value) {
	return /^[A-Z](?=.*[0-9!@#$%^&*]).{7,}$/.test(String(value));
}

function validateStudentAddForm(event) {
	const fields = ['username', 'password', 'firstName', 'lastName', 'email', 'phone', 'dob'];
	clearStudentErrors(fields);

	let valid = true;
	const username = document.getElementById('username')?.value || '';
	const password = document.getElementById('password')?.value || '';
	const firstName = document.getElementById('firstName')?.value || '';
	const lastName = document.getElementById('lastName')?.value || '';
	const email = document.getElementById('email')?.value || '';
	const phone = document.getElementById('phone')?.value || '';
	const dob = document.getElementById('dob')?.value || '';

	if (isBlank(username) || !validateLettersOnly(username)) {
		setFieldError('username', 'Username must contain letters only.');
		valid = false;
	}
	if (isBlank(password)) {
		setFieldError('password', 'Password is required.');
		valid = false;
	} else if (!validatePassword(password)) {
		setFieldError('password', 'Password must start with a capital letter and include at least one number or special character.');
		valid = false;
	}
	if (isBlank(firstName) || !validateLettersOnly(firstName)) {
		setFieldError('firstName', 'First name must contain letters only.');
		valid = false;
	}
	if (isBlank(lastName) || !validateLettersOnly(lastName)) {
		setFieldError('lastName', 'Last name must contain letters only.');
		valid = false;
	}
	if (isBlank(email) || !validateEmail(email)) {
		setFieldError('email', 'Please enter a valid email address.');
		valid = false;
	}
	if (isBlank(phone) || !validatePhone(phone)) {
		setFieldError('phone', 'Phone number must be exactly 10 digits.');
		valid = false;
	}
	if (isBlank(dob)) {
		setFieldError('dob', 'Date of birth is required.');
		valid = false;
	}

	if (!valid) event.preventDefault();
}

// Validation for instructor add form (similar rules but without DOB and with license number)
function validateInstructorAddForm(event) {
	const fields = ['username', 'password', 'firstName', 'lastName', 'email', 'phone', 'licenseNumber'];
	clearStudentErrors(fields);

	let valid = true;
	const username = document.getElementById('username')?.value || '';
	const password = document.getElementById('password')?.value || '';
	const firstName = document.getElementById('firstName')?.value || '';
	const lastName = document.getElementById('lastName')?.value || '';
	const email = document.getElementById('email')?.value || '';
	const phone = document.getElementById('phone')?.value || '';
	const licenseNumber = document.getElementById('licenseNumber')?.value || '';

	if (isBlank(username) || !validateLettersOnly(username)) {
		setFieldError('username', 'Username must contain letters only.');
		valid = false;
	}
	if (isBlank(password)) {
		setFieldError('password', 'Password is required.');
		valid = false;
	} else if (!validatePassword(password)) {
		setFieldError('password', 'Password must start with a capital letter and include at least one number or special character.');
		valid = false;
	}
	if (isBlank(firstName) || !validateLettersOnly(firstName)) {
		setFieldError('firstName', 'First name must contain letters only.');
		valid = false;
	}
	if (isBlank(lastName) || !validateLettersOnly(lastName)) {
		setFieldError('lastName', 'Last name must contain letters only.');
		valid = false;
	}
	if (isBlank(email) || !validateEmail(email)) {
		setFieldError('email', 'Please enter a valid email address.');
		valid = false;
	}
	if (!isBlank(phone) && !validatePhone(phone)) {
		setFieldError('phone', 'Phone number must be exactly 10 digits.');
		valid = false;
	}
	if (isBlank(licenseNumber)) {
		setFieldError('licenseNumber', 'License number is required.');
		valid = false;
	}

	if (!valid) {
		console.log('Validation failed for instructor add form');
		event.preventDefault();
	} else {
		console.log('Instructor add form validation passed, submitting...');
	}
}

